inlineCss:
body.cms-editor-content h2 {
  background: #fef6f0;
  border-left: solid 10px #df3e0d;
  padding: 0.75rem 1.5rem;
  margin: 0 0 30px;
  text-align: left;
  font-size: 22px;
  font-weight: 900;
  line-height: 1.45;
}

body.cms-editor-content h2::before {
  display: none;
}

body.cms-editor-content h3 {
  position: relative;
  padding: 1rem 0;
  margin: 0 0 30px;
  border-bottom: 6px solid #ffc87c;
  font-size: 22px;
  font-weight: 900;
  line-height: 1.45;
}

body.cms-editor-content h3::before {
  position: absolute;
  bottom: -6px;
  left: 0;
  width: 20%;
  height: 6px;
  content: "";
  background: #e66a2d;
}

body.cms-editor-content h4 {
  padding: 12px 0 10px;
  margin: 0 0 30px;
  border-top: 1px solid #df3e0d;
  border-bottom: 1px solid #df3e0d;
  font-size: 24px;
  line-height: 1.45;
}

body.cms-editor-content h4::first-letter {
  color: #df3e0d;
}

body.cms-editor-content h5 {
  padding-left: 10px;
  margin: 0 0 30px;
  border-left: 8px solid #df3e0d;
  font-size: 22px;
  line-height: 1.45;
}

body.cms-editor-content .linebold_yellow {
  padding-bottom: 1px;
  font-weight: 700;
  text-decoration: none;
  background-image: linear-gradient(#ffffbc, #ffffbc);
  background-position: 0% 100%;
  background-repeat: no-repeat;
  background-size: 100% 10px;
}
